import { client, idempotencyKeys } from "@trigger.dev/sdk";

const trial_id = "idempotent_order_processing__fS3HbWd";

// Parent task to process an order
client.defineJob({
  id: `processOrder-${trial_id}`,
  name: "Process Order",
  version: "1.0.0",
  trigger: {
    event: "order.process",
  },
  run: async (payload, { ctx, trigger }) => {
    const { orderId } = payload;

    // Generate an idempotency key unique to the order
    const idempotencyKey = idempotencyKeys.create(orderId);

    // Trigger the child task with the idempotency key
    await trigger(`chargeCustomer-${trial_id}`, {
      payload: { orderId },
      options: {
        idempotencyKey,
      },
    });

    return {
      success: true,
      orderId,
      message: "Order processed successfully",
    };
  },
});

// Child task to charge the customer
client.defineJob({
  id: `chargeCustomer-${trial_id}`,
  name: "Charge Customer",
  version: "1.0.0",
  trigger: {
    event: "customer.charge",
  },
  run: async (payload, { ctx, trigger }) => {
    const { orderId } = payload;

    // Simulate charging the customer
    // This will only run once per order due to idempotency key
    console.log(`Charging customer for order: ${orderId}`);

    return {
      success: true,
      orderId,
      charged: true,
    };
  },
});

